;  ペンスキー峠

name = ジョセフの森
insideName = Joseph's Forest
level = 10
bgm = forest
isOutdoor = true
shadow = dark
sky = forest
roof = wood
blank = rock
outfield = soil
external = n:1

; 画像パーツ
━ = wood
ᆖ = stone
‥ = soil
　 = soil
☐ = wood
❖ = soil
⏃ = woods
／ = door
∮ = silver
☗ = gate
︻ = panel
⑴ = bulletin
② = human
⑹ = bulletin

; 移動ポイント
(A) = map:サファイアシティ, enter:サファイアシティ・南東門, ask:Enter town?
(B) = map:ペンスキー峠・峠道, x:1 ,y:58, climb:true
(C) = map:ペンスキー峠・峠道, x:2 ,y:58, climb:true
(D) = map:ラドミラの塔１Ｆ, x:12 ,y:0

; 宝箱
box[1] = 罠はない,鉄の槍,鉄の槍,ボム,ボム,ボム
box[2] = 罠はない,ロングボウ,ジャベリン,アシッドの巻物,アシッドの巻物,アシッドの巻物,ポーション
box[3] = 罠はない,ロングソード,ブロンズバックラー,ボム,ボム,復活の粉
box[4] = アイスロッド,硬い革鎧,モンクの書,金貨（大）

