;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

pos[4][19].f.type = events.has(5) ? "block" : "floor";
bgm = events.has(5) ? "crisis" : "forest";

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Welcome to Sapphire City"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove

@fg c=golem_metal left=450 top=-80
[texton]
In the center of the square stands a giant metal figure. It is what is known as a golem.[k]
The golem seems to have stopped functioning, showing no signs of movement at all.[k]
[textoff]

[if exp='game.isFreeMode']
	@question title="Would you like to look into it?"
	[if exp='tf.result']
		@clf
		@monster pos=3 name=メタルゴーレム
		@callbattle gameover=true
		@changefloor pimg=void
		@delevent
	[endif]
[endif]
@clf

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Armory"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@delevent
@addevent num=5
@eval exp='o.テオ.skill.push2(o.退魔の力)'
@jump storage="main05.scn" target=*golem_2

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] true

@jump storage="main05.scn" target=*golem_3

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@roadguide w="Mountain Pass" e=Armory

[eventoff]
;-------------------------------------------------------------------------------
